CREATE TABLE IF NOT EXISTS ship_event_timeline (internal_id INT, pending BOOLEAN NOT NULL, returned BOOLEAN NOT NULL, demo_url VARCHAR(2048) NOT NULL, repo_url VARCHAR(2048) NOT NULL, devlog_count INT NOT NULL, hour_count INT NOT NULL, attached_mission VARCHAR(30) NULL, description VARCHAR(4500) NOT NULL, request INT, CONSTRAINT pk_ship_event_timeline PRIMARY KEY (internal_id, request), CONSTRAINT fk_ship_event_timeline_internal_id__internal_id FOREIGN KEY (internal_id) REFERENCES ship_events(internal_id) ON DELETE RESTRICT ON UPDATE RESTRICT, CONSTRAINT fk_ship_event_timeline_request__id FOREIGN KEY (request) REFERENCES requests(id) ON DELETE RESTRICT ON UPDATE RESTRICT);